#!/usr/bin/env node
/**
 * Promote the 225 AI-drafted newspaper-scan descriptions into media.json.
 * These go in flagged with needsReview: true so the MediaCard UI shows an
 * "AI draft" badge and a future editorial pass can flip each to false.
 *
 * Attribution.paper + date are derived from the OCR filename (reliable, not
 * AI-generated). Attribution.headline + byline come from the AI draft (may
 * need correction). descriptionShort + descriptionLong come from the AI
 * draft too.
 *
 * Thumbs: /assets/vault/scan-thumbs/<imageId>.jpg (generated by
 * generate-scan-thumbs.mjs, shipped in the public/ bundle).
 * Full scan: /media/scans/<imageId>.jpg (Worker → R2, private only).
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, '..');

const inventory = JSON.parse(fs.readFileSync(path.join(root, 'docs/curation/private-media-inventory.json'), 'utf-8'));
const scans = inventory.scans || [];

const imageIndex = JSON.parse(fs.readFileSync(path.join(root, 'src/data/imageIndex.json'), 'utf-8'));

// Derive paper name + page from the OCR filename slug.
// Filename format: YYYY-MM-DD-paper-slug-pXX-iIIIIII.md
function paperFromFilename(filename) {
  if (!filename) return null;
  const m = filename.match(/^(\d{4}-\d{2}-\d{2})-(.+?)-p(\d+)-i\d{7,}\.md$/);
  if (!m) return null;
  const paperSlug = m[2];
  const page = `p${m[3]}`;
  const paper = paperSlug
    .split('-')
    .map(w => /^(the|of|and|in|on|at|for)$/i.test(w) ? w : w[0].toUpperCase() + w.slice(1))
    .join(' ')
    .replace(/\bNhl\b/, 'NHL')
    .replace(/\bAhl\b/, 'AHL')
    .replace(/\bIhl\b/, 'IHL')
    .replace(/\bBchl\b/, 'BCHL')
    .replace(/\bBcjhl\b/, 'BCJHL')
    .replace(/\bCp\b/, 'CP')
    .replace(/\bUs\b/, 'US')
    .replace(/\bBu\b/, 'BU');
  return { paper, page };
}

const draftsDir = path.join(root, 'docs/curation/drafts');
const mediaPath = path.join(root, 'src/data/media.json');
const media = JSON.parse(fs.readFileSync(mediaPath, 'utf-8'));
const existingIds = new Set(media.map(m => m.id));

let added = 0, skipped = 0, missingDraft = 0;

for (const scan of scans) {
  const id = scan.slugId; // scan-<imageId>
  if (existingIds.has(id)) { skipped++; continue; }

  const draftPath = path.join(draftsDir, `${id}.json`);
  if (!fs.existsSync(draftPath)) { missingDraft++; continue; }
  const draft = JSON.parse(fs.readFileSync(draftPath, 'utf-8'));

  const idx = imageIndex[scan.imageId];
  const date = idx?.date || null;
  const filenameInfo = paperFromFilename(idx?.filename);
  const paper = filenameInfo?.paper || draft.attribution?.paper || 'Unknown paper';
  const page = filenameInfo?.page || draft.attribution?.page || undefined;

  const attribution = {
    paper,
    ...(draft.attribution?.headline ? { headline: draft.attribution.headline } : {}),
    ...(draft.attribution?.byline ? { byline: draft.attribution.byline } : {}),
    ...(page ? { page } : {}),
    imageId: scan.imageId,
  };

  const entry = {
    id,
    type: 'newspaper',
    date: date || '1987-01-01',
    access: 'private',
    thumb: `/assets/vault/scan-thumbs/${scan.imageId}.jpg`,
    descriptionShort: draft.descriptionShort,
    descriptionLong: draft.descriptionLong,
    url: `/media/scans/${scan.imageId}.jpg`,
    attribution,
    tags: Array.isArray(draft.tags) ? draft.tags : [],
    relatedGames: [],
    needsReview: true,
  };

  media.push(entry);
  existingIds.add(id);
  added++;
}

media.sort((a, b) => (a.date || '').localeCompare(b.date || ''));
fs.writeFileSync(mediaPath, JSON.stringify(media, null, 2));

console.log(`media.json: added ${added} scans, skipped ${skipped}, draft-missing ${missingDraft}. Total now: ${media.length}.`);
